// src/popup.ts
var TAXONOMY = taxonomy_default;
var $ = (id) => document.getElementById(id);
var makeEl = $("make");
var modelEl = $("model");
var yearEl = $("year");
var labelEl = $("label");
var link = $("kbb");
var ccLink = $("carcomplaints");
var form = $("form");
var errorEl = $("error");
var loadingEl = $("loading");
var labelTouched = false;
function showError(message) {
  errorEl.textContent = message;
  errorEl.classList.remove("hidden");
}
function fillDatalist(id, values) {
  $(id).replaceChildren(...values.map((v) => {
    const o = document.createElement("option");
    o.value = v;
    return o;
  }));
}
function keys() {
  return {
    make: resolveMakeSlug(makeEl.value),
    model: slugify(modelEl.value),
    year: yearEl.value.trim()
  };
}
function stylesFor(make, model, year) {
  return TAXONOMY[make]?.[model]?.[year];
}
function resolveStyle(styles) {
  const text = labelEl.value.trim();
  if (!text)
    return;
  const t = slugify(text);
  return styles?.find((s) => s.label === text || s.slug === t) ?? { slug: t };
}
function refresh() {
  const { make, model, year } = keys();
  fillDatalist("models", TAXONOMY[make] ? Object.keys(TAXONOMY[make]).sort() : []);
  fillDatalist("years", TAXONOMY[make]?.[model] ? Object.keys(TAXONOMY[make][model]).sort((a, b) => Number(b) - Number(a)) : []);
  const styles = stylesFor(make, model, year);
  fillDatalist("labels", styles ? styles.map((s) => s.label ?? s.slug) : []);
  if (styles?.length && !labelTouched && labelEl.value.trim() === "") {
    labelEl.value = styles[0].label ?? styles[0].slug;
  }
  const yearNum = Number(year);
  if (!make || !model || !year || Number.isNaN(yearNum)) {
    link.classList.add("hidden");
    ccLink.classList.add("hidden");
    return;
  }
  link.href = buildKbbUrl({
    makeSlug: make,
    modelSlug: model,
    year: yearNum,
    style: resolveStyle(styles)
  });
  link.classList.remove("hidden");
  ccLink.href = buildCarComplaintsUrl({ make, model, year: yearNum });
  ccLink.classList.remove("hidden");
}
function prefill(v) {
  if (v) {
    makeEl.value = resolveMakeSlug(v.make);
    modelEl.value = slugify(v.model);
    yearEl.value = String(v.year);
    const style = selectStyle(lookupStyles(TAXONOMY, makeEl.value, modelEl.value, v.year), v.trim);
    if (style)
      labelEl.value = style.label ?? style.slug;
  }
  fillDatalist("makes", Object.keys(TAXONOMY).sort());
  refresh();
}
async function main() {
  labelEl.addEventListener("input", () => {
    labelTouched = true;
  });
  for (const el of [makeEl, modelEl, yearEl, labelEl]) {
    el.addEventListener("input", refresh);
  }
  const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
  if (!tab?.id) {
    loadingEl.classList.add("hidden");
    showError("No active tab.");
    return;
  }
  try {
    const res = await chrome.tabs.sendMessage(tab.id, {
      type: "GET_KBB"
    });
    loadingEl.classList.add("hidden");
    if (!res.ok) {
      showError(res.error);
      return;
    }
    form.classList.remove("hidden");
    prefill(res.vehicle);
  } catch {
    loadingEl.classList.add("hidden");
    showError("Open a Facebook Marketplace vehicle listing, then click the icon.");
  }
}
main();
